INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (311037,311038,10,'Yaron','Manual - direct sequel','Direct sequel and the peak of the Raimi trilogy; essential for anyone who liked the first.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (313459,313478,10,'Yaron','Manual - direct sequel','Empire continues the story directly and deepens every character while raising the stakes.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (313478,313479,9,'Yaron','Manual - direct sequel','Return of the Jedi resolves the cliffhanger ending of Empire; you need both.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (194497,194502,10,'Yaron','Manual - direct sequel','One continuous story split in two; finishing Fellowship leads straight into Two Towers.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (194502,194500,9,'Yaron','Manual - direct sequel','Two Towers builds directly to the battles and conclusion of Return of the King.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (280270,280281,8,'Yaron','Manual - direct sequel','Same franchise and heart; Rocky II continues the underdog arc straight from the first.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (129185,2238,10,'Yaron','Manual - same genre - ancient epic','Both are my favorite ancient-world battle epics; same spectacle, same adrenaline.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (129185,340652,8,'Yaron','Manual - same genre - ancient epic','Same ancient setting and large-scale warfare; a natural watch after Gladiator.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (46169,129185,9,'Yaron','Manual - same theme - revenge epic','Two historical revenge epics; both follow a warrior who loses everything and fights back.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (130953,92573,8,'Yaron','Manual - same franchise - Bond','The two Connery Bonds that define the franchise; the original and its iconic follow-up.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (289109,290070,10,'Yaron','Manual - same director + WWII','Spielberg''s two WWII masterpieces; if one moved you, the other will too.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (257459,121538,8,'Yaron','Manual - same theme - Vietnam War','The two definitive Vietnam War films; both unflinching and essential for war-film fans.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (86274,86279,8,'Yaron','Manual - direct sequel','Same Bruce Willis action formula; the sequel runs it in an airport and still delivers.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (10830,10920,8,'Yaron','Manual - direct sequel','Aliens picks up directly and shifts from horror to action while keeping what made Alien great.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (129185,33923,9,'Yaron','Manual - same genre - Roman epic','Both Roman epics built around a wronged man seeking justice; near-identical emotional arc.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (311037,30955,8,'Yaron','Manual - same genre - superhero','Two films that defined serious superhero cinema; both ground the origin in real emotion.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (289109,39551,9,'Yaron','Manual - same genre - war combat','The two most viscerally realistic modern combat films; both built on chaos and authenticity.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (130945,335336,7,'Yaron','Manual - same franchise - Bond','Two Brosnan-era Bonds that deliver the spy-thriller formula with strong production value.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (319602,319613,7,'Yaron','Manual - direct sequel','Superman II continues directly with Zod as the villain; same charm as the original.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (191246,191244,8,'Yaron','Manual - same franchise - Lion King','Same Lion King world I love; the sequel carries the emotional depth of the original.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (46169,310455,8,'Yaron','Manual - same theme - historical epic','Two sweeping warrior-revolt epics I rate highly; ancient and historical battle at full scale.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (313459,313474,1,'Yaron','Manual - same franchise, quality drop','Same universe but the prequel''s weak characters and slow plot let down fans of the original.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (313478,313476,1,'Yaron','Manual - same franchise, quality drop','Empire is the peak; Attack of the Clones is the weakest entry. Same universe, opposite quality.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (311038,30952,1,'Yaron','Manual - same genre, quality drop','My top superhero film paired with one widely considered the worst; huge quality gap.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (207992,207991,1,'Yaron','Manual - same franchise, quality drop','The first is a great action film; Revolutions drowns in philosophy. Poor follow-up for fans.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (130953,218808,1,'Yaron','Manual - same franchise, quality drop','Goldfinger is Bond at its best; Moonraker in space breaks the spy-thriller credibility.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (280270,280305,2,'Yaron','Manual - same franchise, quality drop','Same franchise but Rocky V is the weakest by far; a big drop from the original.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (238072,238073,2,'Yaron','Manual - same franchise, quality drop','The first is a tight heist; the sequel gets too clever and loses the wit. Weak follow-up.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (130953,354178,2,'Yaron','Manual - same franchise, quality drop','Same franchise, but A View to a Kill is a tired, flat entry next to Goldfinger.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (311038,30965,2,'Yaron','Manual - same genre, quality drop','Spider-Man 2 is the gold standard; Batman Forever is tonally confused. Disappointing follow-up.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (256632,256631,3,'Yaron','Manual - same franchise, similar weakness','Same series and same issues; Pirates 2 is more bloat with diminishing returns.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (129185,25192,2,'Yaron','Manual - tone mismatch','Same production scale but The Aviator is a slow drama; lacks the action Gladiator fans want.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (86274,346059,3,'Yaron','Manual - same genre, weaker copy','Same premise but Under Siege lacks the wit, script and star power that made Die Hard iconic.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (289109,250861,4,'Yaron','Manual - same genre, tone mismatch','Both war films but Patton is a slow, theatrical character study; very different from Ryan''s intensity.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (96593,65811,3,'Yaron','Manual - same director, tone mismatch','Both Spielberg alien films but Close Encounters is slow awe where E.T. is warm adventure.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (332065,218808,3,'Yaron','Manual - same franchise, tone mismatch','Same series but Moonraker is the franchise at its silliest; a clear tone and quality mismatch.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (335835,109421,5,'Yaron','Manual - similar surface, depth gap','Both glossy adrenaline films, but Top Gun has emotional weight where F&F is mostly surface.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (86274,346060,4,'Yaron','Manual - same genre, weaker copy','Same template but Under Siege 2 is a tired sequel; thin script and weaker execution.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (162380,30952,1,'Yaron','Manual - same genre, quality drop','Both superhero films but at opposite ends of quality; Batman and Robin is widely mocked.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (129185,10331,4,'Yaron','Manual - same genre, weak entry','Both are ancient-world epics, but Alexander is a flat, overlong slog next to Gladiator; a weak recommendation despite the shared setting.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (2238,10331,4,'Yaron','Manual - same genre, weak entry','Both depict ancient warfare, but Alexander lacks the propulsive energy of 300 and disappoints on the same battlefield.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (328285,262647,4,'Yaron','Manual - same genre, weak entry','Both are sci-fi action films, but Predator 2 is a weaker city-set sequel that doesn''t match the relentless drive of The Terminator.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (113504,190869,2,'Yaron','Manual - same genre, disliked target','Both are animated films, but Lilo & Stitch didn''t land for me, making it a weak follow-up to a film as strong as Finding Nemo.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (207992,310957,3,'Yaron','Manual - same genre, weak entry','Both are sci-fi films, but Sphere''s slow underwater mystery lacks the kinetic energy that makes The Matrix great.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (141544,90771,4,'Yaron','Manual - same genre, weaker','Both are crime films with strong leads, but Donnie Brasco''s slower, quieter register is a step down from the scale and tension of Heat.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (311038,30967,3,'Yaron','Manual - same genre, weak entry','Both are superhero films, but Batman Returns is cold and distant next to the warmth and craft of Spider-Man 2.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (215879,208503,4,'Yaron','Manual - same genre, weak entry','Both are action films, but Maximum Risk is disposable next to the spectacle and energy of Mission: Impossible II.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (46169,279581,5,'Yaron','Manual - same theme, smaller scale','Both are Scottish Highland warrior films, but Rob Roy is a quieter, smaller story that lacks Braveheart''s epic sweep.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (289109,210671,5,'Yaron','Manual - same genre, milder','Both are WWII films, but Memphis Belle is far milder and more conventional than the visceral intensity of Saving Private Ryan.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (191246,47865,5,'Yaron','Manual - same genre, lesser','Both are Disney animal films, but Brother Bear is a lesser entry that doesn''t reach the emotional heights of The Lion King.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (188507,139169,4,'Yaron','Manual - same genre, weaker','Both are action films, but Hard Target is a hollow, style-over-substance piece next to the sharp buddy chemistry of Lethal Weapon.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (310726,318163,4,'Yaron','Manual - same genre, weak entry','Both are high-concept action thrillers, but Sudden Death is a thin Van Damme vehicle next to the relentless craft of Speed.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (271095,228313,5,'Yaron','Manual - same genre, lightweight','Both are treasure-hunt adventures, but National Treasure is a lightweight imitation that lacks the craft of Raiders of the Lost Ark.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (131780,294855,4,'Yaron','Manual - same genre, slower','Both are crime films, but Serpico''s slow-burn character study is a quieter, less gripping watch than Goodfellas.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (73436,346059,3,'Yaron','Manual - same genre, weaker','Both are military action films, but Under Siege lacks the script and tension that make Crimson Tide''s submarine standoff so gripping.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (335835,47435,5,'Yaron','Manual - same genre, lesser','Both are military action films, but Broken Arrow is a lesser Travolta vehicle that doesn''t match the passion and craft of Top Gun.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (35522,213231,4,'Yaron','Manual - same genre, milder','Both are action-comedies, but Midnight Run''s gentler road-trip humor lacks the explosive energy of Beverly Hills Cop.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (176712,176711,7,'Yaron','Auto - 10 common actors','Kill Bill was shot as one film; Vol. 1 is the more kinetic half and essential viewing for anyone who saw Vol. 2.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (280115,20371,6,'Yaron','Auto - 10 common actors','Both are loud, high-stakes Bruckheimer-style action spectacles; a fan of The Rock will find the same energy in Armageddon.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (280282,280270,7,'Yaron','Auto - 11 common actors','Same franchise; Rocky is the original that started it all and the natural watch for anyone who enjoyed Rocky III.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (312170,117314,6,'Yaron','Auto - 11 common actors','Both are Roger Moore-era Bond films with the same tone and style; a natural match within the franchise.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (280282,280281,6,'Yaron','Auto - 12 common actors','Same franchise and crowd-pleasing formula; Rocky II sits right alongside Rocky III in quality and tone.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (280281,280270,7,'Yaron','Auto - 13 common actors','Same franchise; Rocky II continues directly from the original, which remains the strongest entry.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (313479,313459,8,'Yaron','Auto - 13 common actors','Both are core entries in the original Star Wars trilogy; essential viewing for any fan of one.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (30965,30952,1,'Yaron','Auto - 14 common actors','Both are Schumacher-era Batman films widely seen as the weakest of the series; recommending one to a fan of the other offers little.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139657,139652,7,'Yaron','Auto - 15 common actors','Both are Harry Potter entries in the same continuous story; Goblet of Fire raises the stakes and is a natural next watch.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (313478,313459,8,'Yaron','Auto - 15 common actors','Both are pillars of the original Star Wars trilogy; the original is essential for anyone who loved Empire.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (313479,313478,9,'Yaron','Auto - 15 common actors','Same trilogy; Empire is the high point of the saga and mandatory for any Return of the Jedi fan.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (319613,319602,7,'Yaron','Auto - 16 common actors','Same franchise; the original Superman sets up everything and is the stronger of the two films.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139652,139650,6,'Yaron','Auto - 19 common actors','Both Harry Potter films from the same continuous story; a fan of one will want the other.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (14132,14131,7,'Yaron','Auto - 20 common actors','Same franchise and comic ensemble; the original American Pie has the same energy fans of the sequel enjoy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139655,139652,7,'Yaron','Auto - 20 common actors','Consecutive Harry Potter films with the same cast and rising stakes; an easy recommendation for any fan.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (311038,311037,9,'Yaron','Auto - 20 common actors','Same trilogy; the original Spider-Man sets up everything that makes Spider-Man 2 great and is essential viewing.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (337168,337166,4,'Yaron','Auto - 20 common actors','Both Toy Story films share the same style; competent and warm, but neither fully landed for me, so this is a lukewarm recommendation.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (194502,194497,9,'Yaron','Auto - 22 common actors','Both are core LOTR entries from one continuous story; Fellowship is essential for any Two Towers fan.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (313476,313474,2,'Yaron','Auto - 22 common actors','Both are prequel-trilogy entries I found weak; recommending one to a fan of the other adds little.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (194500,194497,9,'Yaron','Auto - 23 common actors','Both are pillars of the LOTR trilogy; Fellowship begins the story and is essential for anyone who saw Return of the King.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139657,139655,7,'Yaron','Auto - 25 common actors','Both Harry Potter films in the same saga; Azkaban is widely seen as the turning point and a strong next watch.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (139655,139650,6,'Yaron','Auto - 28 common actors','Consecutive Harry Potter films with the same cast; a natural recommendation within the series.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (33923,30965,2,'Yaron','Auto - 3 common genres, 36 year gap','Despite a shared genre tag, a sweeping Roman epic and a campy 90s Batman have little in common, and Batman Forever is a weak watch.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (240521,30959,3,'Yaron','Auto - 3 common genres, 36 year gap','A 1960s Bond film and a brooding Batman reboot share little beyond an action label, and Batman Begins isn''t the kind of superhero film I enjoy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (279581,33923,6,'Yaron','Auto - 3 common genres, 36 year gap','Both are period epics built on honor and combat; a Rob Roy fan may well appreciate the grander scale of Ben-Hur despite the era gap.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (368418,120574,6,'Yaron','Auto - 3 common genres, 36 year gap','Both are Bond films; the leaner, more grounded From Russia with Love is a strong watch even for fans of the later entries.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (372233,207989,4,'Yaron','Auto - 3 common genres, 36 year gap','A 1960s spy adventure and a sci-fi action sequel share only a broad action label; limited overlap makes this a weak match.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (372233,207991,1,'Yaron','Auto - 3 common genres, 36 year gap','Beyond a generic action tag these two have nothing in common, and Matrix Revolutions is the weakest of its trilogy.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (310455,112205,5,'Yaron','Auto - 3 common genres, 37 year gap','A Roman epic and a colourful sci-fi adventure make an odd pair; both are strong films, but a fan of one has no clear reason to expect the other.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (372233,79716,4,'Yaron','Auto - 3 common genres, 37 year gap','A spy adventure and a climate-disaster spectacle overlap only loosely; the connection is thin.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (372233,311038,5,'Yaron','Auto - 3 common genres, 37 year gap','Spider-Man 2 is excellent, but a 1960s Bond film is a strange gateway to it; the pairing is weak despite the quality of the target.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (78530,33923,4,'Yaron','Auto - 3 common genres, 38 year gap','A volcano-disaster film and a Roman epic share little; Ben-Hur is the far better film but not an obvious match for a Dante''s Peak fan.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (112205,33923,5,'Yaron','Auto - 3 common genres, 38 year gap','Both are spectacle-driven epics in their way, but the sci-fi and ancient-Rome divide makes this only a loose recommendation.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (130953,86263,2,'Yaron','Auto - 3 common genres, 38 year gap','Both are Bond films, but Die Another Day is the franchise at its most over-the-top and a clear step down from Goldfinger.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (310455,289109,6,'Yaron','Auto - 3 common genres, 38 year gap','Both are large-scale, brutal depictions of men at war; a Spartacus fan drawn to its battles will find the same intensity in Saving Private Ryan.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (372233,30959,3,'Yaron','Auto - 3 common genres, 38 year gap','A classic Bond and a grounded Batman reboot share only an action label, and Batman Begins isn''t the kind of superhero film I gravitate to.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (372233,313477,5,'Yaron','Auto - 3 common genres, 38 year gap','A 1960s spy film and a Star Wars prequel have little in common beyond spectacle; the match is weak despite Sith being the best of the prequels.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (120574,86263,2,'Yaron','Auto - 3 common genres, 39 year gap','Both are Bond, but Die Another Day''s gadget-heavy excess is a long way from the lean tension of From Russia with Love.');
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`comment`,`justification`) VALUES (214755,120574,5,'Yaron','Auto - 3 common genres, 39 year gap','Both are sharp, tense thrillers, but the sci-fi and spy divide plus the decades between them make this only a loose recommendation.');
